import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import Dataset, DataLoader
import torchvision.models as models
import torchvision.transforms as transforms
from torchvision.datasets import ImageFolder
import requests
import os
from pathlib import Path
import hashlib
from tqdm import tqdm


class ModelDownloader:
    def __init__(self, cache_dir='./model_cache'):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
    
    def download_from_url(self, url, filename=None):
        if filename is None:
            filename = hashlib.md5(url.encode()).hexdigest() + '.pth'
        
        filepath = self.cache_dir / filename
        
        if filepath.exists():
            print(f"Model already cached at {filepath}")
            return str(filepath)
        
        print(f"Downloading model from {url}")
        response = requests.get(url, stream=True)
        response.raise_for_status()
        
        total_size = int(response.headers.get('content-length', 0))
        
        with open(filepath, 'wb') as f, tqdm(
            desc=filename,
            total=total_size,
            unit='iB',
            unit_scale=True,
            unit_divisor=1024,
        ) as pbar:
            for chunk in response.iter_content(chunk_size=8192):
                size = f.write(chunk)
                pbar.update(size)
        
        print(f"Model downloaded to {filepath}")
        return str(filepath)
    
    def load_checkpoint(self, path_or_url, map_location=None):
        if path_or_url.startswith('http://') or path_or_url.startswith('https://'):
            local_path = self.download_from_url(path_or_url)
        else:
            local_path = path_or_url
        
        if map_location is None:
            map_location = torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        
        checkpoint = torch.load(local_path, map_location=map_location)
        return checkpoint


class TransferLearningModel(nn.Module):
    def __init__(self, base_model, num_classes, freeze_base=True):
        super(TransferLearningModel, self).__init__()
        self.base_model = base_model
        
        if freeze_base:
            for param in self.base_model.parameters():
                param.requires_grad = False
        
        if hasattr(base_model, 'fc'):
            in_features = base_model.fc.in_features
            self.base_model.fc = nn.Linear(in_features, num_classes)
        elif hasattr(base_model, 'classifier'):
            if isinstance(base_model.classifier, nn.Sequential):
                in_features = base_model.classifier[-1].in_features
                base_model.classifier[-1] = nn.Linear(in_features, num_classes)
            else:
                in_features = base_model.classifier.in_features
                base_model.classifier = nn.Linear(in_features, num_classes)
        elif hasattr(base_model, 'head'):
            in_features = base_model.head.in_features
            self.base_model.head = nn.Linear(in_features, num_classes)
    
    def forward(self, x):
        return self.base_model(x)


class CustomDataset(Dataset):
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
    
    def __len__(self):
        return len(self.data)
    
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
        
        return sample, label


class TransferLearningPipeline:
    def __init__(self, model_name='resnet50', num_classes=10, device=None):
        self.model_name = model_name
        self.num_classes = num_classes
        self.device = device if device else torch.device('cuda' if torch.cuda.is_available() else 'cpu')
        self.downloader = ModelDownloader()
        self.model = None
        
    def load_pretrained_model(self, checkpoint_url=None, freeze_base=True):
        if checkpoint_url:
            checkpoint = self.downloader.load_checkpoint(checkpoint_url, map_location=self.device)
            
            if self.model_name == 'resnet50':
                base_model = models.resnet50(weights=None)
            elif self.model_name == 'resnet18':
                base_model = models.resnet18(weights=None)
            elif self.model_name == 'vgg16':
                base_model = models.vgg16(weights=None)
            elif self.model_name == 'efficientnet_b0':
                base_model = models.efficientnet_b0(weights=None)
            else:
                raise ValueError(f"Unsupported model: {self.model_name}")
            
            if 'state_dict' in checkpoint:
                base_model.load_state_dict(checkpoint['state_dict'])
            elif 'model_state_dict' in checkpoint:
                base_model.load_state_dict(checkpoint['model_state_dict'])
            else:
                base_model.load_state_dict(checkpoint)
        else:
            if self.model_name == 'resnet50':
                base_model = models.resnet50(weights=models.ResNet50_Weights.IMAGENET1K_V1)
            elif self.model_name == 'resnet18':
                base_model = models.resnet18(weights=models.ResNet18_Weights.IMAGENET1K_V1)
            elif self.model_name == 'vgg16':
                base_model = models.vgg16(weights=models.VGG16_Weights.IMAGENET1K_V1)
            elif self.model_name == 'efficientnet_b0':
                base_model = models.efficientnet_b0(weights=models.EfficientNet_B0_Weights.IMAGENET1K_V1)
            else:
                raise ValueError(f"Unsupported model: {self.model_name}")
        
        self.model = TransferLearningModel(base_model, self.num_classes, freeze_base=freeze_base)
        self.model.to(self.device)
        
        return self.model
    
    def prepare_data_loaders(self, train_data_path, val_data_path=None, batch_size=32, 
                            image_size=224, use_imagefolder=True):
        transform = transforms.Compose([
            transforms.Resize((image_size, image_size)),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
        
        if use_imagefolder:
            train_dataset = ImageFolder(train_data_path, transform=transform)
            train_loader = DataLoader(train_dataset, batch_size=batch_size, shuffle=True, num_workers=4)
            
            if val_data_path:
                val_dataset = ImageFolder(val_data_path, transform=transform)
                val_loader = DataLoader(val_dataset, batch_size=batch_size, shuffle=False, num_workers=4)
            else:
                val_loader = None
        else:
            train_loader = DataLoader(train_data_path, batch_size=batch_size, shuffle=True, num_workers=4)
            val_loader = DataLoader(val_data_path, batch_size=batch_size, shuffle=False, num_workers=4) if val_data_path else None
        
        return train_loader, val_loader
    
    def fine_tune(self, train_loader, val_loader=None, epochs=10, learning_rate=0.001, 
                  save_path='./checkpoints', save_best=True):
        if self.model is None:
            raise ValueError("Model not loaded. Call load_pretrained_model first.")
        
        os.makedirs(save_path, exist_ok=True)
        
        criterion = nn.CrossEntropyLoss()
        optimizer = optim.Adam(filter(lambda p: p.requires_grad, self.model.parameters()), 
                              lr=learning_rate)
        scheduler = optim.lr_scheduler.StepLR(optimizer, step_size=5, gamma=0.1)
        
        best_val_acc = 0.0
        history = {'train_loss': [], 'train_acc': [], 'val_loss': [], 'val_acc': []}
        
        for epoch in range(epochs):
            print(f"\nEpoch {epoch+1}/{epochs}")
            print("-" * 50)
            
            self.model.train()
            train_loss = 0.0
            train_correct = 0
            train_total = 0
            
            train_pbar = tqdm(train_loader, desc=f"Training")
            for inputs, labels in train_pbar:
                inputs, labels = inputs.to(self.device), labels.to(self.device)
                
                optimizer.zero_grad()
                outputs = self.model(inputs)
                loss = criterion(outputs, labels)
                loss.backward()
                optimizer.step()
                
                train_loss += loss.item() * inputs.size(0)
                _, predicted = torch.max(outputs, 1)
                train_total += labels.size(0)
                train_correct += (predicted == labels).sum().item()
                
                train_pbar.set_postfix({
                    'loss': f"{loss.item():.4f}",
                    'acc': f"{100 * train_correct / train_total:.2f}%"
                })
            
            epoch_train_loss = train_loss / train_total
            epoch_train_acc = 100 * train_correct / train_total
            history['train_loss'].append(epoch_train_loss)
            history['train_acc'].append(epoch_train_acc)
            
            print(f"Train Loss: {epoch_train_loss:.4f}, Train Acc: {epoch_train_acc:.2f}%")
            
            if val_loader:
                self.model.eval()
                val_loss = 0.0
                val_correct = 0
                val_total = 0
                
                with torch.no_grad():
                    val_pbar = tqdm(val_loader, desc=f"Validation")
                    for inputs, labels in val_pbar:
                        inputs, labels = inputs.to(self.device), labels.to(self.device)
                        
                        outputs = self.model(inputs)
                        loss = criterion(outputs, labels)
                        
                        val_loss += loss.item() * inputs.size(0)
                        _, predicted = torch.max(outputs, 1)
                        val_total += labels.size(0)
                        val_correct += (predicted == labels).sum().item()
                        
                        val_pbar.set_postfix({
                            'loss': f"{loss.item():.4f}",
                            'acc': f"{100 * val_correct / val_total:.2f}%"
                        })
                
                epoch_val_loss = val_loss / val_total
                epoch_val_acc = 100 * val_correct / val_total
                history['val_loss'].append(epoch_val_loss)
                history['val_acc'].append(epoch_val_acc)
                
                print(f"Val Loss: {epoch_val_loss:.4f}, Val Acc: {epoch_val_acc:.2f}%")
                
                if save_best and epoch_val_acc > best_val_acc:
                    best_val_acc = epoch_val_acc
                    checkpoint_path = os.path.join(save_path, f'{self.model_name}_best.pth')
                    torch.save({
                        'epoch': epoch,
                        'model_state_dict': self.model.state_dict(),
                        'optimizer_state_dict': optimizer.state_dict(),
                        'val_acc': best_val_acc,
                        'history': history
                    }, checkpoint_path)
                    print(f"Best model saved to {checkpoint_path}")
            
            scheduler.step()
            
            checkpoint_path = os.path.join(save_path, f'{self.model_name}_epoch_{epoch+1}.pth')
            torch.save({
                'epoch': epoch,
                'model_state_dict': self.model.state_dict(),
                'optimizer_state_dict': optimizer.state_dict(),
                'history': history
            }, checkpoint_path)
        
        print("\nTraining completed!")
        return history
    
    def unfreeze_layers(self, num_layers=None):
        if self.model is None:
            raise ValueError("Model not loaded.")
        
        if num_layers is None:
            for param in self.model.base_model.parameters():
                param.requires_grad = True
            print("All layers unfrozen")
        else:
            layers = list(self.model.base_model.children())
            for layer in layers[-num_layers:]:
                for param in layer.parameters():
                    param.requires_grad = True
            print(f"Last {num_layers} layers unfrozen")
    
    def evaluate(self, test_loader):
        if self.model is None:
            raise ValueError("Model not loaded.")
        
        self.model.eval()
        test_correct = 0
        test_total = 0
        
        with torch.no_grad():
            for inputs, labels in tqdm(test_loader, desc="Evaluating"):
                inputs, labels = inputs.to(self.device), labels.to(self.device)
                outputs = self.model(inputs)
                _, predicted = torch.max(outputs, 1)
                test_total += labels.size(0)
                test_correct += (predicted == labels).sum().item()
        
        test_acc = 100 * test_correct / test_total
        print(f"Test Accuracy: {test_acc:.2f}%")
        return test_acc


def main():
    pipeline = TransferLearningPipeline(model_name='resnet50', num_classes=10)
    
    model = pipeline.load_pretrained_model(freeze_base=True)
    
    train_loader, val_loader = pipeline.prepare_data_loaders(
        train_data_path='./data/train',
        val_data_path='./data/val',
        batch_size=32
    )
    
    history = pipeline.fine_tune(
        train_loader=train_loader,
        val_loader=val_loader,
        epochs=10,
        learning_rate=0.001,
        save_path='./checkpoints'
    )
    
    pipeline.unfreeze_layers(num_layers=2)
    
    history = pipeline.fine_tune(
        train_loader=train_loader,
        val_loader=val_loader,
        epochs=5,
        learning_rate=0.0001,
        save_path='./checkpoints'
    )
    
    test_loader, _ = pipeline.prepare_data_loaders(
        train_data_path='./data/test',
        batch_size=32
    )
    pipeline.evaluate(test_loader)


if __name__ == '__main__':
    main()